/* public-counts.js — hydrate [data-stat-key] hooks from /_data/public_counts.json.
 *
 * Pages render a static fallback value inside each <span data-stat-key="…">
 * (and the matching legacy <span data-fact="…">). On load we fetch the JSON
 * generated by scripts/generate_public_counts.py and replace the text node
 * with the live value, formatted with Japanese number grouping.
 *
 * Failure mode: if the fetch fails, the static fallback stays. No error UI is
 * shown — the values are still useful even when slightly stale.
 */
(function () {
  "use strict";
  if (typeof document === "undefined") return;

  function fmt(value) {
    if (value === null || value === undefined) return null;
    if (typeof value === "number") {
      try { return value.toLocaleString("ja-JP"); } catch (_e) { return String(value); }
    }
    return String(value);
  }

  function hydrate(data) {
    var nodes = document.querySelectorAll("[data-stat-key]");
    nodes.forEach(function (el) {
      var key = el.getAttribute("data-stat-key");
      if (!key || !(key in data)) return;
      var value = data[key];
      var formatted = fmt(value);
      if (formatted === null) return;
      var target = el.querySelector(".public-count-value") || el;
      target.textContent = formatted;
    });
  }

  function load() {
    var nodes = document.querySelectorAll("[data-stat-key]");
    if (!nodes.length) return;
    var ctrl = (typeof AbortController !== "undefined") ? new AbortController() : null;
    var timer = ctrl ? setTimeout(function () { ctrl.abort(); }, 8000) : null;
    var opts = { cache: "no-cache" };
    if (ctrl) opts.signal = ctrl.signal;
    fetch("/_data/public_counts.json", opts)
      .then(function (r) { if (!r.ok) throw new Error("public_counts fetch failed: " + r.status); return r.json(); })
      .then(hydrate)
      .catch(function () { /* keep fallback values */ })
      .then(function () { if (timer) clearTimeout(timer); });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", load);
  } else {
    load();
  }
})();
